-- Residentado Médico Perú — banco piloto
-- Ejecuta este archivo en el SQL Editor de tu proyecto Supabase.

create extension if not exists pgcrypto;

create table if not exists public.questions (
  id text primary key,
  year integer,
  exam text,
  test text,
  question_number integer,
  area text,
  specialty text,
  topic text,
  subtopic text,
  question text,
  option_a text,
  option_b text,
  option_c text,
  option_d text,
  option_e text,
  official_answer text,
  official_answer_text text,
  key_detection_method text,
  key_verification_status text,
  key_visual_fill text,
  key_visual_bbox text,
  source_pdf text,
  source_page integer,
  source_sha256 text,
  content_sha256 text,
  traceability_complete boolean,
  extraction_status text,
  medical_review_status text,
  explanation_status text,
  correct_explanation text,
  why_not_a text,
  why_not_b text,
  why_not_c text,
  why_not_d text,
  why_not_e text,
  exam_pearl text,
  update_alert text,
  reference_notes text,
  record_version text,
  import_batch text,
  active boolean default true,
  audit_status text,
  audit_current_assessment text,
  audit_current_answer text,
  audit_app_behavior text,
  audit_source_urls text,
  audit_date text
);

create table if not exists public.attempts (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  question_id text not null references public.questions(id) on delete cascade,
  selected_answer text null check (selected_answer is null or selected_answer in ('A','B','C','D','E')),
  is_correct boolean not null,
  response_time_ms integer not null default 0 check (response_time_ms >= 0),
  study_mode text not null default 'continue',
  timed_out boolean not null default false,
  answered_at timestamptz not null default now()
);

create index if not exists attempts_user_answered_idx
  on public.attempts (user_id, answered_at desc);

create index if not exists attempts_user_question_idx
  on public.attempts (user_id, question_id);

alter table public.questions enable row level security;
alter table public.attempts enable row level security;

drop policy if exists "questions_read_authenticated" on public.questions;
create policy "questions_read_authenticated"
on public.questions
for select
to authenticated
using (active = true);

drop policy if exists "attempts_select_own" on public.attempts;
create policy "attempts_select_own"
on public.attempts
for select
to authenticated
using ((select auth.uid()) = user_id);

drop policy if exists "attempts_insert_own" on public.attempts;
create policy "attempts_insert_own"
on public.attempts
for insert
to authenticated
with check ((select auth.uid()) = user_id);

drop policy if exists "attempts_update_own" on public.attempts;
create policy "attempts_update_own"
on public.attempts
for update
to authenticated
using ((select auth.uid()) = user_id)
with check ((select auth.uid()) = user_id);

drop policy if exists "attempts_delete_own" on public.attempts;
create policy "attempts_delete_own"
on public.attempts
for delete
to authenticated
using ((select auth.uid()) = user_id);

revoke all on table public.questions from anon, authenticated;
grant select on table public.questions to authenticated;

revoke all on table public.attempts from anon, authenticated;
grant select, insert, update, delete on table public.attempts to authenticated;


-- Carga/actualización idempotente de las 20 preguntas del piloto.
insert into public.questions (id, year, exam, test, question_number, area, specialty, topic, subtopic, question, option_a, option_b, option_c, option_d, option_e, official_answer, official_answer_text, key_detection_method, key_verification_status, key_visual_fill, key_visual_bbox, source_pdf, source_page, source_sha256, content_sha256, traceability_complete, extraction_status, medical_review_status, explanation_status, correct_explanation, why_not_a, why_not_b, why_not_c, why_not_d, why_not_e, exam_pearl, update_alert, reference_notes, record_version, import_batch, active, audit_status, audit_current_assessment, audit_current_answer, audit_app_behavior, audit_source_urls, audit_date)
values
('RM-2024-A-001', 2024, 'Residentado Médico Perú', 'A', 1, 'Pediatría', 'Otorrinolaringología pediátrica', 'Sinusitis', 'Diagnóstico', 'Niño de 6 años, presenta hace 7 días rinorrea mucopurulenta, tos persistente que se intensifica al correr y cefalea. Antecedente: rinitis alérgica con corticoides intranasales en 3 episodios similares al año. Examen: T° 36.5 °C, FC 85 X´; secreción purulenta en rinofaringe posterior; resto no contributorio. ¿Cuál es el examen diagnóstico de elección?', 'Microbiología', 'Tomografía', 'Serología', 'Radiografía', null, 'D', 'Radiografía', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.97,127.22,540.10,139.94', '2024 ESPECIALIADAD A.pdf', 1, 'dc3bd5da40436c820a1ddf9046bf185b5accb714d64c7e0203ba120ca77f376a', 'a41a8b09e593398448e3dd177c0eb0339844c3369c3db759924bfef079000c36', true, 'ESTRUCTURA_REVISADA', 'OBSERVADA_DESACTUALIZADA', 'COMPLETA_REVISADA', 'Clave oficial del PDF: D, radiografía. Históricamente se usó la radiografía de senos paranasales para buscar opacificación, engrosamiento mucoso o niveles hidroaéreos. Sin embargo, esta pregunta queda observada: en la práctica pediátrica actual la sinusitis bacteriana aguda no complicada se diagnostica clínicamente y no se recomienda imagen rutinaria. Además, 7 días de síntomas sin inicio grave ni doble empeoramiento no bastan, por sí solos, para el criterio clásico de persistencia.', 'La microbiología no se obtiene de forma rutinaria. Un cultivo nasal o nasofaríngeo no identifica de manera fiable al germen sinusal; la aspiración del seno se reserva para situaciones seleccionadas.', 'La tomografía no es el examen rutinario de una sinusitis aguda no complicada; se reserva para sospecha de complicación orbitaria/intracraneal, enfermedad refractaria o planificación quirúrgica.', 'La serología no tiene utilidad para confirmar una sinusitis bacteriana aguda común.', null, null, 'Sinusitis bacteriana pediátrica: pensar en persistencia ≥10 días sin mejoría, inicio grave o empeoramiento tras mejoría inicial. Caso no complicado = diagnóstico clínico, sin imagen rutinaria.', 'Clave histórica desactualizada respecto de guías actuales; no usar radiografía rutinaria para confirmar sinusitis aguda no complicada.', 'La clave oficial D (radiografía) no es compatible con las recomendaciones pediátricas actuales para sinusitis aguda no complicada: el diagnóstico es clínico y no se recomienda imagen rutinaria. Además, 7 días de síntomas sin inicio grave ni empeoramiento no cumplen por sí solos el criterio clásico de persistencia ≥10 días para sinusitis bacteriana aguda.', '0.3', 'PILOTO-2026-07-14', true, 'OBSERVADA_DESACTUALIZADA', 'La clave oficial D (radiografía) no es compatible con las recomendaciones pediátricas actuales para sinusitis aguda no complicada: el diagnóstico es clínico y no se recomienda imagen rutinaria. Además, 7 días de síntomas sin inicio grave ni empeoramiento no cumplen por sí solos el criterio clásico de persistencia ≥10 días para sinusitis bacteriana aguda.', 'Ninguna de las alternativas: diagnóstico clínico; sin imagen rutinaria en caso no complicado.', 'Conservar la clave oficial D para modo histórico, mostrar alerta visible y excluirla del puntaje de dominio/maestría por defecto.', 'https://publications.aap.org/pediatriccare/article/doi/10.1542/aap.ppcqr.396228/139/Sinusitis', '2026-07-14'),
('RM-2024-A-002', 2024, 'Residentado Médico Perú', 'A', 2, 'Medicina Interna', 'Neumología', 'EPOC', 'Espirometría', 'Varón de 77 años, fumador, acude por presentar tos productiva crónica, astenia, disnea de esfuerzo y últimamente de reposo, anorexia y baja de peso. Se le realiza espirometría: VEF1/CVF < 70% (post broncodilatadores). ¿Cuál es el patrón?', 'Normal', 'Obstructivo', 'Restrictivo', 'Mixto', null, 'B', 'Obstructivo', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '55.20,202.94,281.33,215.66', '2024 ESPECIALIADAD A.pdf', 1, 'dc3bd5da40436c820a1ddf9046bf185b5accb714d64c7e0203ba120ca77f376a', '99c04fa07001fe0ac5d4c4a19d590544c25d323a246a281826998a97be9a60ac', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'Un VEF1/CVF posbroncodilatador <0,70 demuestra limitación persistente al flujo aéreo, es decir, un patrón obstructivo. En un adulto mayor fumador con clínica respiratoria crónica, este hallazgo es compatible con EPOC.', 'Un patrón normal no presenta una relación VEF1/CVF reducida por debajo del umbral diagnóstico.', null, 'El patrón restrictivo se caracteriza principalmente por disminución de la capacidad vital y de los volúmenes pulmonares, con una relación VEF1/CVF normal o aumentada; la restricción se confirma con volúmenes pulmonares.', 'Un patrón mixto requiere datos de obstrucción y restricción. La relación baja demuestra obstrucción, pero con la información dada no se ha demostrado disminución de la capacidad pulmonar total.', null, 'EPOC: VEF1/CVF posbroncodilatador <0,70 = obstrucción persistente.', null, 'VEF1/CVF posbroncodilatador <0,70 corresponde a un patrón obstructivo y es el criterio espirométrico requerido para confirmar obstrucción persistente compatible con EPOC.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'VEF1/CVF posbroncodilatador <0,70 corresponde a un patrón obstructivo y es el criterio espirométrico requerido para confirmar obstrucción persistente compatible con EPOC.', 'B. Obstructivo', 'Puntuar normalmente.', 'https://goldcopd.org/spirometry-quick-guide/', '2026-07-14'),
('RM-2024-A-003', 2024, 'Residentado Médico Perú', 'A', 3, 'Medicina Interna', 'Endocrinología', 'Cetoacidosis diabética', 'Clasificación de severidad', 'Mujer de 46 años, acude por dolor abdominal, náusea y vómitos. Antecedentes: diabetes mellitus con tratamiento irregular. Examen: PA 90/60 mmHg, FC 100 X'', FR 28 X'', somnolienta. Laboratorio: glucosa 380 mg/dl; examen de orina: leucocituria y cuerpos cetónicos presentes, gasometría: pH 7.10, bicarbonato 14 mEq/l. ¿Cuál es el grado de severidad?', 'Severa', 'Moderada', 'Grave', 'Leve', null, 'B', 'Moderada', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '55.20,278.81,281.33,291.41', '2024 ESPECIALIADAD A.pdf', 1, 'dc3bd5da40436c820a1ddf9046bf185b5accb714d64c7e0203ba120ca77f376a', 'b8c2d983f5cc65487a8e2843fc5d6477e3dbe0ce265cd08ccfc79643e06d1875', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'La paciente tiene cetoacidosis diabética y la magnitud de la acidosis es compatible con severidad moderada: pH 7,10 y bicarbonato 14 mEq/L. El compromiso del sensorio refuerza que no se trata de una forma leve.', 'La categoría severa se reserva para una acidosis más profunda y mayor compromiso clínico; con bicarbonato 14 mEq/L, la clasificación que mejor encaja es moderada.', null, '“Grave” no constituye una categoría distinta de “severa” en la clasificación estándar leve/moderada/severa; además, la alternativa oficial que corresponde a estos valores es moderada.', 'La CAD leve presenta una acidosis menos intensa; pH 7,10 y HCO3 14 mEq/L exceden el rango de una forma leve.', null, 'CAD: la severidad se clasifica por la magnitud de la acidosis (pH/bicarbonato) y el estado clínico, no por la glucosa aislada.', null, 'pH 7,10 y bicarbonato 14 mEq/L encajan en cetoacidosis diabética moderada; la somnolencia también es compatible con mayor compromiso clínico que una CAD leve.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'pH 7,10 y bicarbonato 14 mEq/L encajan en cetoacidosis diabética moderada; la somnolencia también es compatible con mayor compromiso clínico que una CAD leve.', 'B. Moderada', 'Puntuar normalmente.', 'https://diabetesjournals.org/care/article-pdf/47/8/1257/780938/dci240032.pdf', '2026-07-14'),
('RM-2024-A-004', 2024, 'Residentado Médico Perú', 'A', 4, 'Gineco-Obstetricia', 'Obstetricia', 'Restricción del crecimiento fetal', 'Conducta obstétrica', 'Primigesta de 38 semanas, acude por presentar disminución de movimientos fetales. Examen: PA 130/90 mmHg, FC 72 X''. Altura uterina 28 cm. SPP: LCI, LCF: 140 X''. Ecografía obstétrica: gestación única activa con ponderado fetal percentil 1 y perfil biofísico 6/10. ¿Cuál es la conducta a seguir?', 'Evolución espontánea de parto', 'Cesárea a las 40 semanas', 'Terminar la gestación', 'Control en una semana con doppler', null, 'C', 'Terminar la gestación', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.97,341.93,540.10,354.53', '2024 ESPECIALIADAD A.pdf', 1, 'dc3bd5da40436c820a1ddf9046bf185b5accb714d64c7e0203ba120ca77f376a', 'eed21c095d54b9797228f795b48b446a8ee263357a8b412134cfe36ef94f2487', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'A las 38 semanas, un ponderado fetal en percentil 1 constituye restricción grave del crecimiento fetal. En este contexto, la gestación ya está a término y el perfil biofísico es 6/10, por lo que corresponde culminar la gestación en lugar de diferirla.', 'Esperar evolución espontánea prolonga una gestación con restricción grave y bienestar fetal no completamente tranquilizador.', 'Diferir hasta las 40 semanas no es apropiado en una restricción grave ya diagnosticada a las 38 semanas.', null, 'Un control recién en una semana retrasa una conducta que ya está indicada por la edad gestacional y la severidad del crecimiento restringido.', null, 'RCIU/FGR grave: EFW <p3. A término, la conducta suele ser culminar; el Doppler ayuda a decidir el momento antes del término.', null, 'A las 38 semanas, un peso fetal estimado <p3 constituye restricción grave del crecimiento y ya tiene indicación de culminación; un perfil biofísico 6/10 refuerza la necesidad de no diferir la conducta.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'A las 38 semanas, un peso fetal estimado <p3 constituye restricción grave del crecimiento y ya tiene indicación de culminación; un perfil biofísico 6/10 refuerza la necesidad de no diferir la conducta.', 'C. Terminar la gestación', 'Puntuar normalmente.', 'https://publications.smfm.org/publications/289-society-for-maternal-fetal-medicine-consult-series-52/', '2026-07-14'),
('RM-2024-A-005', 2024, 'Residentado Médico Perú', 'A', 5, 'Salud Pública', 'Gestión sanitaria', 'Dengue', 'Acción intersectorial y determinantes', 'En el ámbito sanitario de una red integrada de servicio de salud (RISS), se presenta un brote de dengue con incremento diario de casos. ¿Qué estrategia debe priorizar el equipo de gestión para reducir la incidencia?', 'Implementar nuevo servicio de cuidados intensivos', 'Incrementar el requerimiento de medicamentos e insumos', 'Solicitar contrato de personal especializado', 'Acción intersectorial y abordaje de los determinantes', null, 'D', 'Acción intersectorial y abordaje de los determinantes', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '55.20,442.85,540.10,455.45', '2024 ESPECIALIADAD A.pdf', 1, 'dc3bd5da40436c820a1ddf9046bf185b5accb714d64c7e0203ba120ca77f376a', 'd68b9bcc7dabc95a3d6f01c9f1f2c3b98d473bd72ab99565dd71cfe3b2dd0028', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'Si el objetivo es reducir la incidencia de dengue, debe actuarse sobre la transmisión y sus determinantes: control vectorial, ambiente, agua, residuos, participación comunitaria y coordinación intersectorial. Aumentar capacidad hospitalaria mejora la respuesta a los casos, pero no reduce por sí mismo la aparición de nuevos casos.', 'Una nueva UCI mejora capacidad para tratar dengue grave, pero es una intervención asistencial y no corta la transmisión.', 'Aumentar medicamentos e insumos prepara la atención de enfermos; no modifica directamente los determinantes que generan nuevos casos.', 'Contratar personal especializado puede ampliar la respuesta sanitaria, pero no es la estrategia poblacional principal para reducir incidencia.', null, null, 'Incidencia de dengue ↓ = intervenir transmisión y determinantes; letalidad ↓ = mejorar diagnóstico y atención oportuna.', null, 'Para reducir incidencia de dengue, la intervención prioritaria debe actuar sobre transmisión y determinantes mediante coordinación intersectorial e intervención integrada, no solo ampliar capacidad asistencial para tratar casos.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'Para reducir incidencia de dengue, la intervención prioritaria debe actuar sobre transmisión y determinantes mediante coordinación intersectorial e intervención integrada, no solo ampliar capacidad asistencial para tratar casos.', 'D. Acción intersectorial y abordaje de los determinantes', 'Puntuar normalmente.', 'https://iris.who.int/bitstreams/324aeff7-417c-4afe-8588-53b85b774ec2/download', '2026-07-14'),
('RM-2024-B-001', 2024, 'Residentado Médico Perú', 'B', 1, 'Cirugía', 'Traumatología', 'Bursitis de rodilla', 'Bursitis prepatelar', 'Mujer de 45 años, que labora como operaria de limpieza, relata que los últimos cuatro días tuvo que refregar pisos en posición de rodillas ocasionándole dolor y aumento de volumen de la rodilla derecha que dificulta la deambulación y sus actividades habituales. ¿Cuál es la lesión anatómica más probable?', 'Rótula', 'Meniscos', 'Bursa de la rodilla', 'Ligamento cruzado', null, 'C', 'Bursa de la rodilla', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.97,114.62,540.10,127.22', '2024 ESPECIALIADAD B.pdf', 1, 'd287aa82a3b73ec5c0945c08b6ac9cff30ed14e1f9160a2fd677f64d16b99066', '7c25a01f3872792cedd5217172533dcc135d9661376ffb372a29fbdb25f0c73c', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'Arrodillarse repetidamente produce presión y microtrauma sobre la bursa prepatelar, causando bursitis prepatelar, clásicamente asociada a trabajos realizados de rodillas.', 'Una lesión de la rótula suele relacionarse con trauma directo importante y puede producir fractura, no este cuadro típico por sobreuso y presión repetida.', 'Las lesiones meniscales suelen asociarse a torsión, dolor en la interlínea, bloqueo o chasquidos, no a presión repetida anterior al arrodillarse.', null, 'Una lesión del ligamento cruzado suele ocurrir por mecanismo de pivotaje o desaceleración y produce inestabilidad, no una tumefacción prepatelar por arrodillarse.', null, '“Rodilla de la criada” / housemaid''s knee = bursitis prepatelar por arrodillarse repetidamente.', null, 'La presión repetida al permanecer de rodillas se asocia clásicamente con bursitis prepatelar; entre las alternativas, la estructura lesionada es la bursa de la rodilla.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'La presión repetida al permanecer de rodillas se asocia clásicamente con bursitis prepatelar; entre las alternativas, la estructura lesionada es la bursa de la rodilla.', 'C. Bursa de la rodilla', 'Puntuar normalmente.', null, '2026-07-14'),
('RM-2024-B-002', 2024, 'Residentado Médico Perú', 'B', 2, 'Cirugía', 'Cirugía digestiva', 'Complicaciones de pancreatitis', 'Seudoquiste pancreático', 'Mujer de 70 años con diagnóstico de pancreatitis biliar grave hace un mes y medio, actualmente refiere dolor persistente en epigastrio, náusea y llenura precoz. Examen de abdomen: se palpa tumoración de 15x15 cm, poco movil y de bordes irregulares. ¿Cuál es el diagnóstico probable?', 'Neoplasia pancreática', 'Acumulación de líquido pancreático', 'Acumulación necrótica aguda', 'Seudoquiste pancreático', null, 'D', 'Seudoquiste pancreático', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.97,202.94,540.10,215.66', '2024 ESPECIALIADAD B.pdf', 1, 'd287aa82a3b73ec5c0945c08b6ac9cff30ed14e1f9160a2fd677f64d16b99066', 'e10a9e6641c9ab20a4fe2b8d7f926365425f81eca5507f8c13f41cde5b8bf985', true, 'ESTRUCTURA_REVISADA', 'VALIDADA_CON_CAVEAT', 'COMPLETA_REVISADA', 'La clave oficial es seudoquiste pancreático. Una colección que persiste más de 4 semanas después de pancreatitis y se vuelve organizada/encapsulada puede corresponder a seudoquiste si contiene esencialmente líquido y no necrosis. El tiempo de un mes y medio favorece una colección pancreática madura.', 'La relación temporal con una pancreatitis grave hace más probable una complicación local pospancreatitis que una neoplasia de nueva presentación.', 'La colección líquida pancreática aguda se usa para colecciones tempranas, típicamente dentro de las primeras 4 semanas y sin una pared bien definida.', 'La colección necrótica aguda también corresponde a una fase temprana, <4 semanas. Después de 4 semanas, si hay necrosis encapsulada, el término correcto es necrosis encapsulada (walled-off necrosis), que no aparece como alternativa.', null, null, 'Atlanta revisada: <4 sem = colección aguda; >4 sem y encapsulada = seudoquiste si es líquida, necrosis encapsulada si contiene detritos necróticos.', 'El enunciado no aporta imagen ni contenido de la colección; en pancreatitis necrotizante tardía debe considerarse necrosis encapsulada.', 'A las 6 semanas de una pancreatitis, una colección encapsulada sin necrosis corresponde a seudoquiste. Sin embargo, tras pancreatitis grave/necrotizante también puede existir necrosis encapsulada (walled-off necrosis), que requiere imagen para diferenciarse. La alternativa C ''acumulación necrótica aguda'' no corresponde por el tiempo >4 semanas.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA_CON_CAVEAT', 'A las 6 semanas de una pancreatitis, una colección encapsulada sin necrosis corresponde a seudoquiste. Sin embargo, tras pancreatitis grave/necrotizante también puede existir necrosis encapsulada (walled-off necrosis), que requiere imagen para diferenciarse. La alternativa C ''acumulación necrótica aguda'' no corresponde por el tiempo >4 semanas.', 'D. Seudoquiste pancreático, si la colección es líquida y sin necrosis.', 'Puntuar normalmente, pero mostrar caveat de nomenclatura de Atlanta después de responder.', 'https://gut.bmj.com/content/early/2012/10/24/gutjnl-2012-302779?versioned=true', '2026-07-14'),
('RM-2024-B-003', 2024, 'Residentado Médico Perú', 'B', 3, 'Pediatría', 'Dermatología pediátrica', 'Escabiosis', 'Tratamiento tópico', 'Lactante de 10 meses, irritable, piel con lesiones papulares eritematosas en abdomen, axilas, codos y muslos, algunas costras en palmas y plantas. Madre presenta lesiones similares en abdomen. ¿Cuál es el tratamiento tópico de elección?', 'Tacrolimus', 'Lindano', 'Permetrina al 5%', 'Mometasona al 1%', null, 'C', 'Permetrina al 5%', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.97,253.46,540.10,266.06', '2024 ESPECIALIADAD B.pdf', 1, 'd287aa82a3b73ec5c0945c08b6ac9cff30ed14e1f9160a2fd677f64d16b99066', '8893883592c4c0a1291cf386ea04d15a6cb0abdcecb01ad57d86d6259ae62e80', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'El cuadro es compatible con escabiosis: prurito, distribución típica en lactante —incluidas palmas y plantas— y contacto domiciliario afectado. La permetrina al 5% es tratamiento tópico de primera línea y puede utilizarse en mayores de 2 meses.', 'Tacrolimus es un inmunomodulador usado en dermatitis atópica; no erradica Sarcoptes scabiei.', 'El lindano no es de primera línea por su potencial neurotoxicidad y debe evitarse especialmente en lactantes y niños pequeños.', null, 'La mometasona puede disminuir inflamación y prurito, pero no elimina el ácaro y puede enmascarar el cuadro.', null, 'Escabiosis en lactantes puede comprometer palmas, plantas y cuero cabelludo. Tratar también contactos estrechos y medidas sobre ropa/ropa de cama.', null, 'La permetrina tópica al 5% es tratamiento de primera línea para escabiosis y puede usarse desde los 2 meses de edad; el lactante tiene 10 meses.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'La permetrina tópica al 5% es tratamiento de primera línea para escabiosis y puede usarse desde los 2 meses de edad; el lactante tiene 10 meses.', 'C. Permetrina al 5%', 'Puntuar normalmente.', 'https://www.cdc.gov/scabies/hcp/clinical-care/index.html', '2026-07-14'),
('RM-2024-B-004', 2024, 'Residentado Médico Perú', 'B', 4, 'Pediatría', 'Emergencias pediátricas', 'Reanimación cardiopulmonar', 'Relación compresión-ventilación', 'En la RCP básica de alta calidad del lactante y niño, se recomienda iniciar compresiones y ventilaciones ...... con un solo reanimador.', '30/2', '15/2', '40/1', '40/2', null, 'A', '30/2', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '55.20,316.61,281.33,329.21', '2024 ESPECIALIADAD B.pdf', 1, 'd287aa82a3b73ec5c0945c08b6ac9cff30ed14e1f9160a2fd677f64d16b99066', '59c634f69298b9f9af1f02f399abf30b34216ed37ee732bf180130614a4332ed', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'En RCP pediátrica sin vía aérea avanzada, un solo reanimador utiliza 30 compresiones por 2 ventilaciones. Cuando hay dos reanimadores en un niño prepúber, la relación cambia a 15:2.', null, '15:2 corresponde al esquema de dos reanimadores en lactantes y niños prepúberes, no a un solo reanimador.', '40:1 no es una relación recomendada de RCP pediátrica.', '40:2 no es una relación recomendada de RCP pediátrica.', null, 'Pediatría: 1 reanimador = 30:2; 2 reanimadores = 15:2 en prepuberales.', null, 'En lactantes y niños con un solo reanimador, la relación compresión:ventilación es 30:2; 15:2 corresponde a dos reanimadores.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'En lactantes y niños con un solo reanimador, la relación compresión:ventilación es 30:2; 15:2 corresponde a dos reanimadores.', 'A. 30/2', 'Puntuar normalmente.', 'https://www.ahajournals.org/doi/10.1161/CIR.0000000000000901', '2026-07-14'),
('RM-2024-B-005', 2024, 'Residentado Médico Perú', 'B', 5, 'Pediatría', 'Neonatología', 'Ictericia neonatal', 'Fallo de la lactancia', 'Neonato de 5 días, es traído por madre quien refiere notarlo muy amarillo. Nacido de parto eutócico, peso al nacer: 3500 g, adecuado para la edad gestacional; luego de alta conjunta, recibe lactancia materna exclusiva. Peso actual 3200 g, ictericia hasta raíz de muslos, presencia de reflejo de búsqueda y succión. ¿Cuál es la causa más probable de la ictericia?', 'Incompatibilidad Rh', 'Fallo de la lactancia', 'Hepatitis del RN', 'Cefalohematoma', null, 'B', 'Fallo de la lactancia', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '55.20,404.93,281.33,417.65', '2024 ESPECIALIADAD B.pdf', 1, 'd287aa82a3b73ec5c0945c08b6ac9cff30ed14e1f9160a2fd677f64d16b99066', '0fcdaaa6b950d337998fc339d653ab406a2796b11fc9ecc0883917c7bba05b01', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'A los 5 días, el neonato ha perdido 300 g de 3500 g, aproximadamente 8,6% del peso de nacimiento. En un lactante con lactancia exclusiva, esto sugiere ingesta insuficiente y aumento de la circulación enterohepática de bilirrubina: la denominada ictericia por ingesta subóptima, históricamente llamada “fallo de la lactancia”.', 'La enfermedad hemolítica por incompatibilidad Rh suele producir ictericia precoz, con frecuencia dentro de las primeras 24 horas, y puede acompañarse de anemia.', null, 'La hepatitis neonatal suele producir hiperbilirrubinemia conjugada/colestasis y otros datos de enfermedad, no este patrón típico de ingesta subóptima.', 'Un cefalohematoma aumentaría la carga de bilirrubina, pero el enunciado no describe una colección hemática en el cuero cabelludo.', null, 'Día 3-5 + pérdida ponderal excesiva + lactancia ineficaz = ictericia por ingesta subóptima. Diferenciar de ictericia por leche materna más tardía.', 'Terminología actual preferible: ictericia por ingesta subóptima (suboptimal intake jaundice).', 'Ictericia al día 5 en lactancia materna exclusiva con pérdida ponderal de 300 g/3500 g (≈8,6%) orienta a hiperbilirrubinemia por ingesta subóptima/fallo de la lactancia más que a hemólisis, hepatitis o cefalohematoma.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'Ictericia al día 5 en lactancia materna exclusiva con pérdida ponderal de 300 g/3500 g (≈8,6%) orienta a hiperbilirrubinemia por ingesta subóptima/fallo de la lactancia más que a hemólisis, hepatitis o cefalohematoma.', 'B. Fallo de la lactancia', 'Puntuar normalmente.', 'https://publications.aap.org/pediatrics/article/150/1/e2022057988/188347/Policy-Statement-Breastfeeding-and-the-Use-of', '2026-07-14'),
('RM-2025-A-001', 2025, 'Residentado Médico Perú', 'A', 1, 'Medicina Interna', 'Cardiología', 'Emergencia hipertensiva', 'Tratamiento inicial', 'Varón de 65 años con antecedente de hipertensión arterial, acude por cefalea intensa, convulsiones y edema de papila. Examen: PA: 190/120 mmHg. ¿Cuál es el medicamento inicial a usar?', 'Labetalol', 'Hidralazina', 'Nitroprusiato', 'Nitroglicerina', null, 'C', 'Nitroprusiato', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.92,102.00,540.00,114.60', '2025 ESPECIALIADAD A.pdf', 1, 'cc4fe7436f2a408360bc265d87e287971212b37e169c1a17b134bc4e596540ce', '824df1efb0109f937a4e47de1877999960a8534d603895f2fe62e913506262be', true, 'ESTRUCTURA_REVISADA', 'OBSERVADA_AMBIGUA', 'COMPLETA_REVISADA', 'Clave oficial CONAREME: C, nitroprusiato. El paciente tiene una emergencia hipertensiva con daño neurológico agudo compatible con encefalopatía hipertensiva; el nitroprusiato es un vasodilatador IV potente y titulable que históricamente se ha utilizado para reducir rápidamente la presión arterial. La pregunta queda marcada como ambigua porque labetalol también es una opción IV defendible y frecuentemente preferida en protocolos actuales.', 'Labetalol NO es claramente incorrecto: es un antihipertensivo IV ampliamente utilizado en emergencias hipertensivas. Su presencia como alternativa hace que la pregunta no tenga una única respuesta indiscutible según guías contemporáneas.', 'La hidralazina tiene una respuesta menos predecible y no suele ser la primera elección general para encefalopatía hipertensiva; tiene usos particulares, como ciertos contextos obstétricos.', null, 'La nitroglicerina es especialmente útil cuando predomina isquemia miocárdica o edema agudo de pulmón; no es la opción general preferida para encefalopatía hipertensiva.', null, 'Emergencia hipertensiva = PA severamente elevada + daño agudo de órgano blanco. Usar fármaco IV titulable; la elección depende del órgano afectado.', 'Pregunta con más de una opción IV defendible según guías/protocolos contemporáneos.', 'El cuadro es una emergencia hipertensiva con encefalopatía. El nitroprusiato es un antihipertensivo IV utilizable, pero no es una respuesta única: labetalol también es un agente recomendado y suele preferirse en muchos protocolos neurológicos por su perfil y titulación. Por ello, con A y C disponibles, la pregunta no tiene una única alternativa indiscutible según guías actuales.', '0.3', 'PILOTO-2026-07-14', true, 'OBSERVADA_AMBIGUA', 'El cuadro es una emergencia hipertensiva con encefalopatía. El nitroprusiato es un antihipertensivo IV utilizable, pero no es una respuesta única: labetalol también es un agente recomendado y suele preferirse en muchos protocolos neurológicos por su perfil y titulación. Por ello, con A y C disponibles, la pregunta no tiene una única alternativa indiscutible según guías actuales.', 'No única: A (labetalol) y C (nitroprusiato) pueden ser defendibles según protocolo; labetalol suele ser preferido.', 'Conservar C como clave oficial; marcar como ambigua y excluir del puntaje de dominio por defecto.', 'https://www.ahajournals.org/doi/10.1161/HYP.0000000000000238', '2026-07-14'),
('RM-2025-A-002', 2025, 'Residentado Médico Perú', 'A', 2, 'Gineco-Obstetricia', 'Patología mamaria', 'Galactorrea', 'Evaluación inicial', 'Mujer de 32 años asintomática que acude por chequeo. Al examen de mama a la expresión de uno de los pezones sale secreción blanco lechoso. ¿Cuál es el manejo más adecuado?', 'Solicitar prolactina', 'Mamografía', 'Ecografía de mamas', 'Observación', null, 'D', 'Observación', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.92,177.72,540.00,190.32', '2025 ESPECIALIADAD A.pdf', 1, 'cc4fe7436f2a408360bc265d87e287971212b37e169c1a17b134bc4e596540ce', 'f8588b8d16eb63f86c2b4706b549adcd7174e9bdb71975b4eefe0c4fa025b032', true, 'ESTRUCTURA_REVISADA', 'VALIDADA_CON_CAVEAT', 'COMPLETA_REVISADA', 'La secreción es blanca, aparece solo al expresar el pezón y la paciente está asintomática. Una secreción provocada y de aspecto fisiológico puede manejarse inicialmente con observación y evitando la estimulación repetida. La pregunta tiene un caveat: la unilateralidad exige vigilar que no se vuelva espontánea, persistente o uniductal.', 'La prolactina se solicita cuando hay verdadera galactorrea persistente o espontánea y/o datos endocrinos como alteraciones menstruales, infertilidad o síntomas de hiperprolactinemia. En una secreción solo provocada y asintomática, no es necesariamente el primer paso.', 'La mamografía no es el primer estudio de una secreción fisiológica provocada en una mujer asintomática; se reserva la imagen para secreción patológica según edad y características.', 'La ecografía tampoco es obligatoria en una secreción claramente fisiológica; sí se indica si la secreción es patológica o aparece una masa/otro hallazgo.', null, null, 'Secreción patológica: espontánea, unilateral/uniductal, sanguinolenta o serosa. Secreción fisiológica: suele ser provocada y no requiere imagen rutinaria.', 'La unilateralidad hace el enunciado menos limpio; vigilar características de secreción patológica.', 'Una secreción lechosa únicamente provocada por expresión, sin síntomas ni masa, puede manejarse con observación y evitar estimulación repetida. No obstante, la unilateralidad es atípica para la secreción fisiológica clásica; si se vuelve espontánea, persistente o de un solo conducto, requiere evaluación dirigida. Si se trata de verdadera galactorrea, debe considerarse prolactina.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA_CON_CAVEAT', 'Una secreción lechosa únicamente provocada por expresión, sin síntomas ni masa, puede manejarse con observación y evitar estimulación repetida. No obstante, la unilateralidad es atípica para la secreción fisiológica clásica; si se vuelve espontánea, persistente o de un solo conducto, requiere evaluación dirigida. Si se trata de verdadera galactorrea, debe considerarse prolactina.', 'D. Observación, aceptable por ser provocada y asintomática.', 'Puntuar normalmente, mostrando caveat sobre unilateralidad y criterios de secreción patológica.', 'https://acsearch.acr.org/docs/3099312/Narrative/', '2026-07-14'),
('RM-2025-A-003', 2025, 'Residentado Médico Perú', 'A', 3, 'Ciencias Básicas', 'Embriología', 'Implantación', 'Sitio de implantación', '¿Cuál es el sitio más frecuente de implantación del blastocisto?', 'Fondo uterino', 'Segmento inferior del útero', 'Cérvix uterino', 'Cuerno uterino', null, 'A', 'Fondo uterino', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '55.20,215.64,281.28,228.24', '2025 ESPECIALIADAD A.pdf', 1, 'cc4fe7436f2a408360bc265d87e287971212b37e169c1a17b134bc4e596540ce', 'c0aba502f0460fcc0b5991187c8eee8bb1d354a79b51dc92cd1431f37f35526d', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'La implantación normal ocurre con mayor frecuencia en el endometrio de la porción superior del cuerpo uterino, habitualmente cerca del fondo y con frecuencia en la pared posterior.', null, 'La implantación en el segmento uterino inferior se asocia a placentación baja/placenta previa, no al sitio más frecuente normal.', 'La implantación cervical es ectópica y potencialmente hemorrágica.', 'La implantación en el cuerno uterino corresponde a una localización anormal/intersticial o cornual según el contexto.', null, 'Implantación normal: endometrio del cuerpo uterino alto, típicamente pared posterior cerca del fondo.', null, 'La implantación normal ocurre con mayor frecuencia en el endometrio de la porción superior del cuerpo uterino, habitualmente en la pared posterior cercana al fondo; ''fondo uterino'' es la mejor alternativa disponible.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'La implantación normal ocurre con mayor frecuencia en el endometrio de la porción superior del cuerpo uterino, habitualmente en la pared posterior cercana al fondo; ''fondo uterino'' es la mejor alternativa disponible.', 'A. Fondo uterino', 'Puntuar normalmente.', null, '2026-07-14'),
('RM-2025-A-004', 2025, 'Residentado Médico Perú', 'A', 4, 'Cirugía', 'Trauma', 'Tórax inestable', 'Manejo inicial', 'Varón de 43 años, llevado a urgencias porque sufrió hace 30 minutos impacto de timón en el tórax por accidente de tránsito. Presenta disnea intensa, dolor torácico izquierdo, taquipnea. Examen: PA:80/40 mmHg, FC: 100X'', FR: 36X''; cianosis distal, movimiento paradojal de la pared torácica. RX: múltiples fracturas costales izquierdas. ¿Cuál es la conducta más adecuada?', 'Colocación de catéter central', 'Ventilación no invasiva', 'Fijación costal quirúrgica', 'Intubación orotraqueal', null, 'D', 'Intubación orotraqueal', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.92,316.56,540.00,329.16', '2025 ESPECIALIADAD A.pdf', 1, 'cc4fe7436f2a408360bc265d87e287971212b37e169c1a17b134bc4e596540ce', '9075399ea2420a40e8dabef90808d63c310c171ba9c1222c5f75ad6e9514d6a2', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'El paciente presenta tórax inestable con insuficiencia respiratoria e inestabilidad hemodinámica: disnea intensa, FR 36, cianosis y PA 80/40 mmHg. La prioridad es asegurar la vía aérea y ventilación mediante intubación orotraqueal. La indicación no es el movimiento paradójico aislado, sino el fracaso fisiológico.', 'Un catéter venoso central puede ser útil para manejo hemodinámico, pero no resuelve la amenaza inmediata de ventilación y oxigenación.', 'La ventilación no invasiva puede considerarse en pacientes seleccionados y estables; este paciente está en shock y con compromiso respiratorio grave.', 'La fijación quirúrgica costal puede ser útil en casos seleccionados, pero no precede a la estabilización inicial de vía aérea, respiración y circulación.', null, null, 'Tórax inestable: no todo paciente requiere intubación. Intubar si hay insuficiencia respiratoria, hipoxemia, fatiga o inestabilidad que impida ventilación segura.', 'Perla: no intubar solo por el movimiento paradójico; la indicación aquí es el fracaso respiratorio y la inestabilidad.', 'El tórax inestable por sí solo no obliga a intubar, pero este paciente presenta disnea intensa, FR 36, cianosis, hipoxemia clínica y shock; hay insuficiencia respiratoria/compromiso fisiológico que justifica control definitivo de la vía aérea y ventilación invasiva.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'El tórax inestable por sí solo no obliga a intubar, pero este paciente presenta disnea intensa, FR 36, cianosis, hipoxemia clínica y shock; hay insuficiencia respiratoria/compromiso fisiológico que justifica control definitivo de la vía aérea y ventilación invasiva.', 'D. Intubación orotraqueal', 'Puntuar normalmente.', 'https://www.east.org/education-resources/practice-management-guidelines/details/pulmonary-contusion-and-flail-chest%2C-management-of', '2026-07-14'),
('RM-2025-A-005', 2025, 'Residentado Médico Perú', 'A', 5, 'Medicina Interna', 'Neurología', 'Pares craneales', 'III par craneal', 'Varón de 27 años, acude a consulta por visión doble y caída del párpado derecho. Examen: se evidencia pupila derecha dilatada con incapacidad para mover el ojo hacia el lado nasal ¿Cuál es el par craneal comprometido?', 'VI', 'I', 'III', 'IV', null, 'C', 'III', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.92,367.08,540.00,379.68', '2025 ESPECIALIADAD A.pdf', 1, 'cc4fe7436f2a408360bc265d87e287971212b37e169c1a17b134bc4e596540ce', 'f73986f9ddc2f92e12fae1938d7505a8c8ac7f64e5292d3ba16b1f683563d302', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'El III par craneal (oculomotor) inerva el elevador del párpado, la mayoría de músculos extraoculares y lleva fibras parasimpáticas pupilares. Su lesión puede producir ptosis, midriasis y limitación de la aducción, como en este caso.', 'El VI par inerva el recto lateral; su lesión produce incapacidad para abducir el ojo, no midriasis ni ptosis.', 'El I par es el nervio olfatorio y no controla movimientos oculares ni la pupila.', null, 'El IV par inerva el oblicuo superior; su lesión causa diplopía vertical, sobre todo al mirar abajo y adentro, sin midriasis típica.', null, 'III par: ojo “abajo y afuera” + ptosis; compromiso parasimpático = midriasis. Pupila dilatada dolorosa obliga a pensar en lesión compresiva.', null, 'Ptosis, midriasis y déficit de aducción ocular son compatibles con lesión del III par craneal (oculomotor).', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'Ptosis, midriasis y déficit de aducción ocular son compatibles con lesión del III par craneal (oculomotor).', 'C. III', 'Puntuar normalmente.', null, '2026-07-14'),
('RM-2025-B-001', 2025, 'Residentado Médico Perú', 'B', 1, 'Cirugía', 'Trauma', 'Lesión traqueobronquial', 'Trauma torácico penetrante', 'Varón de 21 años, es trasladado por haber sufrido asalto con arma de fuego, ingresa con disnea y hemoptisis. Examen: PA: 90/50 mmHg, FR: 30X'', FC: 100X'', SatO2: 90%; orificio de entrada a nivel de HTD tercio medio cara anterior, enfisema subcutáneo, MV abolido en HTD. ¿Cuál es la estructura anatómica afectada?', 'Vena cava superior', 'Diafragma', 'Árbol traqueobronquial', 'Arteria torácica interna', null, 'C', 'Árbol traqueobronquial', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.92,114.60,540.00,127.20', '2025 ESPECIALIADAD B.pdf', 1, '535d1af9512f43227302228006f654a2f5e021e2b4c283313aca5de39bb7861c', '21a64716b1c0b39f1437b8231db2ce2591f8ce5dde59e8da6fa5c64017092ef1', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'Disnea, hemoptisis y enfisema subcutáneo tras trauma penetrante sugieren una lesión con fuga de aire y sangrado desde la vía aérea. Entre las alternativas, el árbol traqueobronquial es la estructura que mejor integra estos hallazgos.', 'Una lesión de la vena cava superior produciría principalmente hemorragia masiva y compromiso hemodinámico; no explica bien el enfisema subcutáneo y la hemoptisis.', 'Una lesión diafragmática suele asociarse a trayectos toracoabdominales y herniación de vísceras; no es la mejor explicación para hemoptisis y fuga aérea.', null, 'La arteria torácica interna puede causar hemorragia/hemotórax, pero no explica de forma primaria la hemoptisis y el enfisema subcutáneo.', null, 'Trauma + enfisema subcutáneo importante + fuga aérea/hemoptisis = sospechar lesión traqueobronquial.', null, 'Tras trauma torácico penetrante, la combinación de hemoptisis, enfisema subcutáneo, disnea e importante alteración ventilatoria hace sospechar lesión del árbol traqueobronquial; es la mejor opción ofrecida.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'Tras trauma torácico penetrante, la combinación de hemoptisis, enfisema subcutáneo, disnea e importante alteración ventilatoria hace sospechar lesión del árbol traqueobronquial; es la mejor opción ofrecida.', 'C. Árbol traqueobronquial', 'Puntuar normalmente.', null, '2026-07-14'),
('RM-2025-B-002', 2025, 'Residentado Médico Perú', 'B', 2, 'Pediatría', 'Genética clínica', 'Síndrome de Down', 'Reconocimiento fenotípico', 'RN producto de parto eutócico, EG 38 semanas, APGAR 8-9. Examen: cara: puente nasal aplanado, ojos almendrados con pliegue epicántico, orejas pequeñas. Línea única en la palma de la mano, flacidez y reflejo de succión alterado. ¿Cuál es el síndrome?', 'Crouzon', 'Apert', 'Treacher Collins', 'Down', null, 'D', 'Down', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.92,202.92,540.00,215.64', '2025 ESPECIALIADAD B.pdf', 1, '535d1af9512f43227302228006f654a2f5e021e2b4c283313aca5de39bb7861c', '4a48a4f4dc1c9f6587ea1c5d60c6d22f9457430fd719841e57f27b3063f99f7c', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'La combinación de hipotonía neonatal, puente nasal aplanado, pliegues epicánticos, orejas pequeñas y pliegue palmar único es típica de síndrome de Down, debido en la mayoría de casos a trisomía 21.', 'Crouzon es una craneosinostosis con alteraciones craneofaciales y proptosis; no explica el fenotipo sistémico descrito.', 'Apert combina craneosinostosis con sindactilia marcada de manos y pies, hallazgo no descrito.', 'Treacher Collins produce hipoplasia malar/mandibular y anomalías auriculares, sin el patrón típico de hipotonía y pliegue palmar único de trisomía 21.', null, null, 'Down: hipotonía + epicanto + puente nasal plano + pliegue palmar único; confirmar con estudio citogenético.', null, 'Hipotonía neonatal, puente nasal aplanado, epicanto, orejas pequeñas y pliegue palmar único son hallazgos fenotípicos clásicos compatibles con síndrome de Down.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'Hipotonía neonatal, puente nasal aplanado, epicanto, orejas pequeñas y pliegue palmar único son hallazgos fenotípicos clásicos compatibles con síndrome de Down.', 'D. Down', 'Puntuar normalmente.', null, '2026-07-14'),
('RM-2025-B-003', 2025, 'Residentado Médico Perú', 'B', 3, 'Medicina Interna', 'Nefrología', 'Peritonitis asociada a diálisis peritoneal', 'Tratamiento', 'Mujer de 48 años en diálisis peritoneal desde hace 2 años, presenta fiebre, náusea, dolor y distensión abdominal. Examen: PA: 110/70 mmHg, T°: 38.6 °C; abdomen: RHA presentes, blando, depresible, en catéter de diálisis se evidencia líquido turbio. Laboratorio: recuento celular en líquido peritoneal de 520/µL; PMN: 90%. ¿Cuál es el tratamiento de elección?', 'Gentamicina + vancomicina', 'Vancomicina', 'Ceftriaxona', 'Ceftriaxona + gentamicina', null, 'A', 'Gentamicina + vancomicina', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '55.20,266.04,281.28,278.76', '2025 ESPECIALIADAD B.pdf', 1, '535d1af9512f43227302228006f654a2f5e021e2b4c283313aca5de39bb7861c', '0da63043d552278fc45661ae83fe05c054a56745f55b9695a20dd3be9e7fabf1', true, 'ESTRUCTURA_REVISADA', 'VALIDADA_CON_CAVEAT', 'COMPLETA_REVISADA', 'La paciente cumple criterios de peritonitis asociada a diálisis peritoneal: clínica compatible, efluente turbio y >100 leucocitos/µL con >50% PMN. El tratamiento empírico debe cubrir grampositivos y gramnegativos. Vancomicina + gentamicina es una combinación aceptable entre las alternativas. La vía intraperitoneal suele ser preferida si es factible y no hay sepsis sistémica.', null, 'Vancomicina sola cubre principalmente grampositivos y deja sin cobertura empírica adecuada a los gramnegativos.', 'Ceftriaxona sola no proporciona la cobertura empírica recomendada para todo el espectro, especialmente grampositivos resistentes según epidemiología local.', 'Ceftriaxona + gentamicina concentra la cobertura en gramnegativos y no ofrece la cobertura grampositiva empírica que aporta vancomicina o una cefalosporina de primera generación.', null, 'Peritonitis en diálisis peritoneal: dolor/efluente turbio + WBC >100/µL y PMN >50%. Empírico = cubrir gram+ y gram−; adaptar al antibiograma local.', 'No es un régimen universal único; el esquema empírico depende de sensibilidad local y debe cubrir grampositivos y gramnegativos.', 'El cuadro cumple criterios de peritonitis asociada a diálisis peritoneal. La terapia empírica debe cubrir grampositivos y gramnegativos; vancomicina + un aminoglucósido como gentamicina es un esquema aceptable según susceptibilidad local. La vía intraperitoneal es la preferida cuando es posible y no existe un único esquema universal de ''elección''.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA_CON_CAVEAT', 'El cuadro cumple criterios de peritonitis asociada a diálisis peritoneal. La terapia empírica debe cubrir grampositivos y gramnegativos; vancomicina + un aminoglucósido como gentamicina es un esquema aceptable según susceptibilidad local. La vía intraperitoneal es la preferida cuando es posible y no existe un único esquema universal de ''elección''.', 'A. Gentamicina + vancomicina, como esquema empírico aceptable.', 'Puntuar normalmente, mostrando caveat de vía intraperitoneal y adaptación a epidemiología local.', 'https://ispd.org/wp-content/uploads/2025/09/LI-ET-1.pdf', '2026-07-14'),
('RM-2025-B-004', 2025, 'Residentado Médico Perú', 'B', 4, 'Medicina Interna', 'Patología vascular', 'Tromboangeítis obliterante', 'Histopatología', 'Varón de 35 años, fumador desde los 14 años, presenta frialdad distal asimétrica de extremidades. Examen: pulsos periféricos disminuidos en mano derecha; prueba de Allen (+), presencia de úlcera isquémica en 2° dedo de pie izquierdo. ¿Cuál es la morfología en la anatomía patológica?', 'Engrosamiento de la íntima con placas ateromatosas y trombos superpuestos a placas ulceradas', 'Vasos con inflamación, obstruidos por trombos intraluminales con microabscesos compuestos por neutrófilos', 'Células inflamatorias dispersas, con calcificación y neovascularización con ulceraciones múltiples', 'Vasos con densos cúmulos de células atípicas que revisten la luz vascular, ocluyéndola totalmente', null, 'B', 'Vasos con inflamación, obstruidos por trombos intraluminales con microabscesos compuestos por neutrófilos', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '55.20,354.48,540.00,367.08', '2025 ESPECIALIADAD B.pdf', 1, '535d1af9512f43227302228006f654a2f5e021e2b4c283313aca5de39bb7861c', 'fdac3b7aca9f884cedeb29abd21882e754a5232d09d30797577216aac638dc4c', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'El cuadro clínico corresponde a tromboangeítis obliterante (enfermedad de Buerger) en un fumador joven con isquemia distal. Histológicamente, en la fase aguda hay trombos inflamatorios oclusivos con microabscesos formados por neutrófilos, con relativa preservación de la pared vascular.', 'Describe aterosclerosis: placas ateromatosas de la íntima con trombosis sobre placas complicadas, más típica de enfermedad arterial aterosclerótica.', null, 'La calcificación y neovascularización no describen la lesión histológica clásica de la tromboangeítis obliterante.', 'Cúmulos de células atípicas que revisten y ocluyen vasos sugieren una neoplasia vascular, no una vasculopatía inflamatoria trombótica.', null, 'Buerger = fumador joven + isquemia distal + trombosis inflamatoria segmentaria con microabscesos neutrofílicos. Tratamiento clave: abandono total del tabaco.', null, 'La tromboangeítis obliterante se caracteriza en fase aguda por oclusión trombótica inflamatoria con microabscesos ricos en neutrófilos, con relativa preservación de la pared vascular.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'La tromboangeítis obliterante se caracteriza en fase aguda por oclusión trombótica inflamatoria con microabscesos ricos en neutrófilos, con relativa preservación de la pared vascular.', 'B. Vasos con inflamación y trombos intraluminales con microabscesos de neutrófilos', 'Puntuar normalmente.', 'https://www.ahajournals.org/doi/pdf/10.1161/circulationaha.114.009935', '2026-07-14'),
('RM-2025-B-005', 2025, 'Residentado Médico Perú', 'B', 5, 'Gineco-Obstetricia', 'Uroginecología', 'Prolapso de órganos pélvicos', 'Clasificación POP-Q', 'Mujer de 75 años, acude por sensación de bulto en zona vaginal. No refiere escape de orina. Examen: POPQ: Aa 0, Ba +1; longitud total de la vagina 7 cm. ¿Cuál es el grado del prolapso?', 'IV', 'I', 'II', 'III', null, 'C', 'II', 'Rectángulo vectorial amarillo superpuesto a la alternativa en el PDF original', 'VERIFICADA_PDF_VECTOR', '#FFF215 aprox.', '313.92,430.20,540.00,442.80', '2025 ESPECIALIADAD B.pdf', 1, '535d1af9512f43227302228006f654a2f5e021e2b4c283313aca5de39bb7861c', 'bdb20f24c1c7b43a09463d924f48ea5ed449f9101c24f95cb90fd040ccab1480', true, 'ESTRUCTURA_REVISADA', 'VALIDADA', 'COMPLETA_REVISADA', 'En POP-Q, el estadio II se define cuando el punto más distal del prolapso se encuentra entre 1 cm por encima y 1 cm por debajo del himen. Ba = +1 cm cae exactamente dentro del estadio II.', 'El estadio IV corresponde a eversión vaginal prácticamente completa, mucho más allá de los valores descritos.', 'El estadio I requiere que el borde más distal permanezca más de 1 cm por encima del himen.', null, 'El estadio III requiere que el borde más distal protruda más de 1 cm por debajo del himen, sin llegar a la eversión completa; +1 cm todavía es estadio II.', null, 'POP-Q: II = −1 a +1 cm respecto al himen; III = >+1 cm pero no eversión completa; IV = eversión casi/completamente total.', null, 'En POP-Q, estadio II corresponde a un borde más distal entre −1 y +1 cm respecto del himen. Ba = +1 cm cae exactamente en estadio II; estadio III requiere >+1 cm.', '0.3', 'PILOTO-2026-07-14', true, 'VALIDADA', 'En POP-Q, estadio II corresponde a un borde más distal entre −1 y +1 cm respecto del himen. Ba = +1 cm cae exactamente en estadio II; estadio III requiere >+1 cm.', 'C. II', 'Puntuar normalmente.', 'https://www.ics.org/Wasabi/Documents/DocumentsDownload.aspx?DocumentID=2015', '2026-07-14')
